const client = new MongoClient(uri);

async function run() {
  try {
    const database = client.db("<database>");
    const collection = database.collection("<collection>");

    // Create the MongoDB Search index definition for the geo field
    const index = {
        name: "default",
        definition: {
            "mappings": {
                "dynamic": true|false,
                "fields": {
                    "<field-name>": {
